// Minimal YAML parser for Docker Compose
const lines = input.split('\n');
const services = {};
let currentService = null;
let currentSection = null;
let inServices = false;

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  const indent = line.match(/^(\s*)/)[1].length;
  const trimmed = line.trim();
  if (!trimmed || trimmed.startsWith('#')) continue;

  if (trimmed === 'services:') { inServices = true; continue; }
  if (inServices && indent === 2 && /^[\w-]+:\s*$/.test(trimmed)) {
    currentService = trimmed.replace(':', '').trim();
    services[currentService] = { ports: [], volumes: [], env: [], depends: [], image: '', build: '' };
    currentSection = null;
    continue;
  }
  if (!currentService) continue;
  if (trimmed.startsWith('image:')) {
    services[currentService].image = trimmed.replace('image:', '').trim();
  } else if (trimmed.startsWith('build:')) {
    services[currentService].build = trimmed.replace('build:', '').trim() || '.';
  } else if (trimmed === 'ports:') { currentSection = 'ports'; }
  else if (trimmed === 'volumes:') { currentSection = 'volumes'; }
  else if (trimmed === 'environment:') { currentSection = 'env'; }
  else if (trimmed === 'depends_on:') { currentSection = 'depends'; }
  else if (trimmed.startsWith('-') && currentSection) {
    services[currentService][currentSection].push(trimmed.slice(1).trim());
  } else if (!/^-/.test(trimmed) && trimmed.includes(':') && indent === 4) {
    currentSection = null;
  }
}

const out = [];
for (const [name, s] of Object.entries(services)) {
  out.push(`Service: ${name}`);
  if (s.image)   out.push(`  Image:   ${s.image}`);
  if (s.build)   out.push(`  Build:   ${s.build}`);
  if (s.ports.length)   out.push(`  Ports:   ${s.ports.join(', ')}`);
  if (s.volumes.length) out.push(`  Volumes: ${s.volumes.join(', ')}`);
  if (s.env.length) {
    out.push('  Env vars:');
    s.env.forEach(e => out.push('    ' + e));
  }
  if (s.depends.length) out.push(`  Depends on: ${s.depends.join(', ')}`);
  out.push('');
}
return { output: out.join('\n').trimEnd(), outputLanguage: 'text' };
